SELECT *
FROM file_tbl_file_info
WHERE file_id = #{fileId}
  AND tenant_id = #{tenantId}

SELECT *
FROM file_tbl_file_info
WHERE file_id IN

    #{id}

AND tenant_id = #{tenantId}

SELECT *
FROM file_tbl_file_info
WHERE file_md5 = #{fileMd5}
  AND tenant_id = #{tenantId}
  AND file_status = 1

SELECT COUNT(1)
FROM file_tbl_file_info
WHERE file_name = #{fileName}
  AND tenant_id = #{tenantId}
  AND file_status = 1

SELECT COUNT(1)
FROM file_tbl_file_info
WHERE storage_type = #{storageType}
  AND tenant_id = #{tenantId}
  AND file_status = 1

SELECT COALESCE(SUM(file_size), 0)
FROM file_tbl_file_info
WHERE storage_type = #{storageType}
  AND tenant_id = #{tenantId}
  AND file_status = 1

SELECT *
FROM file_tbl_file_info
WHERE expire_time < #{expireTime}
AND file_status = 2
AND tenant_id = #{tenantId}

    AND storage_type = #{storageType}

SELECT *
FROM file_tbl_file_info
WHERE upload_status = 0
  AND upload_start_time < #{expireTime}
  AND tenant_id = #{tenantId}

SELECT f.*,
       (SELECT COUNT(1) FROM file_version WHERE file_id = f.file_id) AS version_count,
       (SELECT MAX(version) FROM file_version WHERE file_id = f.file_id) AS current_version
FROM file_tbl_file_info f
WHERE f.file_id = #{fileId}
  AND f.tenant_id = #{tenantId}

SELECT *
FROM file_tbl_file_info
WHERE tenant_id = #{tenantId}

    AND file_name LIKE CONCAT('%', #{fileName}, '%')


    AND file_status = #{fileStatus}


    AND storage_type = #{storageType}


    AND business_id = #{businessId}


    AND business_type = #{businessType}


    AND created_user_id = #{uploadUserId}


    AND created_user_name LIKE CONCAT('%', #{uploadUserName}, '%')


    AND created_time >= #{startTime}


    AND created_time <= #{endTime}


    AND file_size >= #{minSize}


    AND file_size <= #{maxSize}


    AND (

        FIND_IN_SET(#{tag}, tags)

    )



        ORDER BY ${orderBy} ${orderDirection}


        ORDER BY created_time DESC


LIMIT #{size} OFFSET #{offset}

SELECT file_id AS fileId, file_name AS fileName, file_size AS fileSize, file_type AS fileType, created_user_id AS uploadUserId, created_user_name AS uploadUserName, created_time AS uploadTime, audit_status AS auditStatus, audit_comment AS auditComment, audit_user_id AS auditUserId, audit_user_name AS auditUserName, audit_time AS auditTime FROM file_tbl_file_info WHERE tenant_id = #{tenantId}
AND audit_status = #{status}
AND file_id = #{fileId}
AND file_name LIKE CONCAT('%', #{fileName}, '%')
AND created_time >= #{startTime}
AND created_time <= #{endTime}
ORDER BY created_time DESC LIMIT #{size} OFFSET #{offset}

SELECT file_md5, file_size, COUNT(1) AS file_count FROM file_tbl_file_info WHERE tenant_id = #{tenantId} AND file_status = 1
AND storage_type = #{storageType}
GROUP BY file_md5, file_size HAVING COUNT(1) > 1

SELECT *
FROM file_tbl_file_info
WHERE file_md5 = #{fileMd5}
  AND file_size = #{fileSize}
  AND tenant_id = #{tenantId}
ORDER BY created_time ASC

SELECT DATE_FORMAT(created_time, '%Y-%m-%d') AS date, COUNT(1) AS uploadCount, SUM(file_size) AS totalSize, COUNT(DISTINCT created_user_id) AS uniqueUsers FROM file_tbl_file_info WHERE tenant_id = #{tenantId} AND created_time BETWEEN #{startDate} AND #{endDate}
AND storage_type = #{storageType}
GROUP BY DATE_FORMAT(created_time, '%Y-%m-%d') ORDER BY date ASC

